import{_ as e,o,c as t,ag as a}from"./chunks/framework.DGzMGr_a.js";const u=JSON.parse('{"title":"浏览器架构：主要有哪些进程和线程？","description":"","frontmatter":{"title":"浏览器架构：主要有哪些进程和线程？","difficulty":"medium","tags":["浏览器架构","进程","线程","Chromium"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-02-browser-architecture.md","filePath":"domains/browser/qa/qa-02-browser-architecture.md","lastUpdated":1783504823000}'),s={name:"domains/browser/qa/qa-02-browser-architecture.md"};function i(l,r,n,c,d,g){return o(),t("div",null,[...r[0]||(r[0]=[a('<h1 id="问答-02-进阶-浏览器架构-主要有哪些进程和线程" tabindex="-1">问答 02（进阶）：浏览器架构：主要有哪些进程和线程？ <a class="header-anchor" href="#问答-02-进阶-浏览器架构-主要有哪些进程和线程" aria-label="Permalink to &quot;问答 02（进阶）：浏览器架构：主要有哪些进程和线程？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>以 Chromium 为例，现代浏览器采用「多进程 + 多线程」架构。请说出主要有哪些进程，每类进程内又有哪些关键线程，以及它们为什么要这样切分。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>为什么多进程</strong></p><ul><li><strong>安全</strong>：渲染引擎跑在沙箱进程里，即使被攻破也拿不到系统权限。</li><li><strong>稳定</strong>：一个 tab 崩了不影响别人，浏览器主进程能重启它。</li><li><strong>性能</strong>：进程之间可以并行调度到多核 CPU。</li></ul><p><strong>Chromium 主要进程</strong></p><ol><li><strong>Browser Process（浏览器主进程）</strong>：只有一个。负责地址栏、书签、窗口管理、进程调度、网络转发、存储管理。是所有其它进程的父进程。</li><li><strong>Renderer Process（渲染进程）</strong>：每个 tab（或每个 site，Site Isolation 开启时按站点隔离）一个，跑 Blink 引擎和 V8。执行 HTML / CSS / JS，做布局、绘制。是沙箱进程，权限最小。</li><li><strong>GPU Process</strong>：处理 GPU 相关任务，把合成结果栅格化上屏；WebGL、Canvas 加速都靠它。全浏览器一个。</li><li><strong>Network Process（网络进程）</strong>：负责 DNS、HTTP(S) 请求、Cookie、缓存等。渲染进程发起请求走 IPC 转到这里。</li><li><strong>Storage Process</strong>：管理 LocalStorage、IndexedDB、Cache Storage 等。</li><li><strong>Plugin Process / Utility Process</strong>：跑插件（Flash 时代产物）、音视频解码等辅助能力。</li><li><strong>Extension Process</strong>：每个扩展一个进程。</li></ol><p><strong>渲染进程内的线程</strong></p><ul><li><strong>主线程（Main Thread）</strong>：解析 HTML / CSS，构建 DOM / CSSOM，执行 JS（V8），布局、绘制的<strong>调度</strong>都在这里。事件循环也跑在这里。</li><li><strong>合成线程（Compositor Thread）</strong>：接收主线程提交的层树，把层切成 tile，交给栅格化线程；直接处理简单的滚动、<code>transform</code>、<code>opacity</code> 动画（合成器动画能跳过主线程，非常流畅）。</li><li><strong>栅格化线程（Raster Threads）</strong>：把 tile 转成位图，通常若干个并行。</li><li><strong>Worker 线程</strong>：Web Worker、Service Worker、Worklet 都跑在独立线程，不阻塞主线程。</li><li><strong>IO 线程</strong>：处理与浏览器主进程之间的 IPC 消息。</li></ul><p><strong>为什么合成器动画不卡</strong></p><ul><li>主线程要跑 JS、布局、绘制，很容易被业务代码阻塞。</li><li>合成线程只做图层组合，即使主线程 100% 忙，<code>transform: translateX(...)</code> 这类动画仍能 60fps 播放。这就是为什么动画尽量用 <code>transform</code> / <code>opacity</code> 而不是 <code>top</code> / <code>left</code>。</li></ul><h2 id="追问-1-site-isolation-是什么-它解决了什么安全问题" tabindex="-1">追问 1：Site Isolation 是什么？它解决了什么安全问题？ <a class="header-anchor" href="#追问-1-site-isolation-是什么-它解决了什么安全问题" aria-label="Permalink to &quot;追问 1：Site Isolation 是什么？它解决了什么安全问题？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>早期一个渲染进程可能同时承载多个跨源 iframe，若被恶意页面利用可以读取其它源的内存。<strong>Spectre / Meltdown</strong> 侧信道攻击揭示了这种风险。</li><li>Site Isolation（Chrome 67+ 默认开启）保证 <strong>每个站点使用独立的渲染进程</strong>，跨源 iframe 会被移到父页面所属站点外的进程里。</li><li>同时配合 <strong>Cross-Origin Read Blocking (CORB / CORP)</strong>，阻断跨源响应进入错误的渲染进程。</li><li>代价：进程数上涨、内存占用增加，但安全收益是必需的。</li></ul><h2 id="追问-2-service-worker、web-worker、worklet-三者跑在什么线程-各自适合什么场景" tabindex="-1">追问 2：Service Worker、Web Worker、Worklet 三者跑在什么线程？各自适合什么场景？ <a class="header-anchor" href="#追问-2-service-worker、web-worker、worklet-三者跑在什么线程-各自适合什么场景" aria-label="Permalink to &quot;追问 2：Service Worker、Web Worker、Worklet 三者跑在什么线程？各自适合什么场景？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Web Worker</strong>：与页面同源的独立线程，用来跑 CPU 密集脚本，不能访问 DOM。通信通过 <code>postMessage</code>，可传 Transferable（<code>ArrayBuffer</code>、<code>MessagePort</code>、<code>ImageBitmap</code>）实现零拷贝。</li><li><strong>Service Worker</strong>：常驻的后台脚本，独立于任何 tab，充当页面与网络之间的代理，能拦截 <code>fetch</code>、做离线缓存、推送。生命周期由浏览器管理，不能长时间挂起同步逻辑。</li><li><strong>Worklet</strong>：更轻量的线程，跑在渲染管线的特定阶段：<code>PaintWorklet</code>（自定义绘制）、<code>AudioWorklet</code>（音频处理）、<code>AnimationWorklet</code>（动画）、<code>LayoutWorklet</code>（实验）。运行时无 DOM，专用 API。</li><li>选择：需要拦截网络 → Service Worker；纯计算 → Web Worker；音频 / 绘制 → Worklet。</li></ul><h2 id="追问-3-为什么「一个-tab-崩了别的不受影响」-跨进程通信开销大不大" tabindex="-1">追问 3：为什么「一个 tab 崩了别的不受影响」？跨进程通信开销大不大？ <a class="header-anchor" href="#追问-3-为什么「一个-tab-崩了别的不受影响」-跨进程通信开销大不大" aria-label="Permalink to &quot;追问 3：为什么「一个 tab 崩了别的不受影响」？跨进程通信开销大不大？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>因为每个 tab 有独立的渲染进程，OS 级别隔离。渲染进程崩溃只会让该 tab 显示「Aw, Snap!」，浏览器主进程能重新拉起。</li><li>跨进程通信通过 <strong>Mojo IPC</strong>（Chromium 内部）实现，走共享内存 + 消息传递，性能已优化到接近函数调用，但仍比同进程调用慢。为此关键路径（如合成）会尽量减少 IPC 跳数，或使用共享内存/<code>SharedArrayBuffer</code> 传大对象。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://developer.chrome.com/blog/inside-browser-part1" target="_blank" rel="noreferrer">Inside look at modern browser</a>：Chromium 多进程架构系列</li><li><a href="https://www.chromium.org/developers/design-documents/multi-process-architecture/" target="_blank" rel="noreferrer">Chromium: Multi-process Architecture</a>：进程隔离、沙箱与安全设计</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/Performance/How_browsers_work" target="_blank" rel="noreferrer">MDN: How browsers work</a>：浏览器进程与线程概览</li></ul>',24)])])}const m=e(s,[["render",i]]);export{u as __pageData,m as default};
